/**
 * Transactions.jsx
 * ─────────────────────────────────────────────────────────────
 * Página de transacciones con:
 * - Formulario para agregar ingresos y gastos
 * - Historial completo con filtros y opción de eliminar
 * - Feedback visual en cada acción
 */

import { useState }                          from 'react'
import { useTransactions }                   from '../hooks/useTransactions'
import { formatCurrency, formatDateShort }   from '../utils/formatCurrency'
import Button                                from '../components/common/Button'
import styles                                from './Transactions.module.css'

const CATEGORIES = [
  'alimentación', 'transporte', 'vivienda', 'salud',
  'entretenimiento', 'educación', 'ropa', 'otros',
]

const CATEGORY_EMOJI = {
  alimentación: '🛒', transporte: '🚗', vivienda: '🏠',
  salud: '💊', entretenimiento: '🎬', educación: '📚',
  ropa: '👕', otros: '📦',
}

const EMPTY_FORM = {
  type: 'expense', description: '', amount: '',
  category: 'alimentación', date: '', notes: '',
}

export default function Transactions() {
  const { transactions, loading, error, addTransaction, removeTransaction } = useTransactions()

  // Estado del formulario
  const [form,      setForm]      = useState(EMPTY_FORM)
  const [saving,    setSaving]    = useState(false)
  const [formError, setFormError] = useState(null)
  const [success,   setSuccess]   = useState(false)

  // Estado de filtros
  const [filterType, setFilterType] = useState('all')
  const [deletingId,  setDeletingId] = useState(null)

  /* ── Manejo del formulario ─────────────────────── */
  const handleChange = (e) => {
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }))
    setFormError(null)
    setSuccess(false)
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setSaving(true)
    setFormError(null)

    try {
      await addTransaction({ ...form, amount: Number(form.amount) })
      setForm(EMPTY_FORM)
      setSuccess(true)
      // Limpiar mensaje de éxito después de 3s
      setTimeout(() => setSuccess(false), 3000)
    } catch (err) {
      setFormError(err.response?.data?.error || 'Error al guardar la transacción.')
    } finally {
      setSaving(false)
    }
  }

  /* ── Eliminar con confirmación visual ──────────── */
  const handleDelete = async (id) => {
    setDeletingId(id)
    try {
      await removeTransaction(id)
    } finally {
      setDeletingId(null)
    }
  }

  /* ── Filtrado del historial ────────────────────── */
  const filtered = filterType === 'all'
    ? transactions
    : transactions.filter((t) => t.type === filterType)

  return (
    <div className={styles.page}>
      {/* Encabezado */}
      <div className={`${styles.pageHeader} animate-fade-up`}>
        <div>
          <h1 className={styles.pageTitle}>Transacciones</h1>
          <p className={styles.pageSubtitle}>Registra y consulta todos tus movimientos</p>
        </div>
      </div>

      <div className={styles.layout}>
        {/* ── Formulario ───────────────────────────── */}
        <div className={`card ${styles.formCard} animate-fade-up delay-1`}>
          <div className="card-header">
            <span className="label">Nueva transacción</span>
          </div>

          <form onSubmit={handleSubmit} className={styles.form} noValidate>
            {/* Toggle tipo */}
            <div className={styles.typeToggle} role="group" aria-label="Tipo de transacción">
              {[
                { value: 'expense', label: 'Gasto',   icon: '↓' },
                { value: 'income',  label: 'Ingreso', icon: '↑' },
              ].map(({ value, label, icon }) => (
                <button
                  key={value}
                  type="button"
                  className={`${styles.typeBtn} ${form.type === value ? styles[`typeActive_${value}`] : ''}`}
                  onClick={() => setForm((f) => ({ ...f, type: value }))}
                  aria-pressed={form.type === value}
                >
                  <span className={styles.typeIcon}>{icon}</span> {label}
                </button>
              ))}
            </div>

            {/* Descripción */}
            <div className="form-group">
              <label className="field-label" htmlFor="description">Descripción</label>
              <input
                id="description" name="description" type="text"
                placeholder="Ej: Mercado del sábado"
                value={form.description}
                onChange={handleChange}
                required
              />
            </div>

            {/* Monto y categoría */}
            <div className="form-row">
              <div className="form-group">
                <label className="field-label" htmlFor="amount">Monto</label>
                <input
                  id="amount" name="amount" type="number"
                  placeholder="0"
                  min="1"
                  value={form.amount}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="form-group">
                <label className="field-label" htmlFor="category">Categoría</label>
                <select
                  id="category" name="category"
                  value={form.category}
                  onChange={handleChange}
                >
                  {CATEGORIES.map((c) => (
                    <option key={c} value={c}>
                      {CATEGORY_EMOJI[c]} {c.charAt(0).toUpperCase() + c.slice(1)}
                    </option>
                  ))}
                </select>
              </div>
            </div>

            {/* Fecha y notas */}
            <div className="form-row">
              <div className="form-group">
                <label className="field-label" htmlFor="date">Fecha</label>
                <input
                  id="date" name="date" type="date"
                  value={form.date}
                  onChange={handleChange}
                />
              </div>
              <div className="form-group">
                <label className="field-label" htmlFor="notes">Notas</label>
                <input
                  id="notes" name="notes" type="text"
                  placeholder="Opcional"
                  value={form.notes}
                  onChange={handleChange}
                />
              </div>
            </div>

            {/* Feedback */}
            {formError && (
              <div className="feedback feedback-error">{formError}</div>
            )}
            {success && (
              <div className="feedback feedback-success">
                ✓ Transacción guardada correctamente
              </div>
            )}

            <Button type="submit" fullWidth size="lg" loading={saving}>
              Guardar transacción
            </Button>
          </form>
        </div>

        {/* ── Historial ────────────────────────────── */}
        <div className={`card ${styles.listCard} animate-fade-up delay-2`}>
          <div className={styles.listHeader}>
            <span className="label">
              Historial{' '}
              <span className={styles.count}>({filtered.length})</span>
            </span>

            {/* Filtros */}
            <div className={styles.filters} role="group" aria-label="Filtrar por tipo">
              {[
                { value: 'all',     label: 'Todos'    },
                { value: 'expense', label: 'Gastos'   },
                { value: 'income',  label: 'Ingresos' },
              ].map(({ value, label }) => (
                <button
                  key={value}
                  className={`${styles.filterBtn} ${filterType === value ? styles.filterActive : ''}`}
                  onClick={() => setFilterType(value)}
                  aria-pressed={filterType === value}
                >
                  {label}
                </button>
              ))}
            </div>
          </div>

          {/* Estado de carga */}
          {loading && (
            <p className={styles.loadingMsg}>Cargando transacciones…</p>
          )}

          {/* Error */}
          {error && (
            <div className="feedback feedback-error">{error}</div>
          )}

          {/* Lista vacía */}
          {!loading && filtered.length === 0 && (
            <div className={styles.emptyState}>
              <span className={styles.emptyIcon}>📭</span>
              <p>No hay transacciones{filterType !== 'all' ? ` de tipo "${filterType}"` : ''}</p>
            </div>
          )}

          {/* Lista */}
          <ul className={styles.list}>
            {filtered.map((t) => (
              <li key={t.id} className={styles.item}>
                <span className={styles.itemEmoji}>
                  {CATEGORY_EMOJI[t.category] || '📦'}
                </span>

                <div className={styles.itemBody}>
                  <p className={styles.itemDesc}>{t.description}</p>
                  <p className={styles.itemMeta}>
                    <span className={`badge ${t.type === 'income' ? 'badge-success' : 'badge-danger'}`}>
                      {t.type === 'income' ? 'Ingreso' : 'Gasto'}
                    </span>
                    <span>{t.category}</span>
                    {t.notes && <span className={styles.notes}>· {t.notes}</span>}
                    <span>{formatDateShort(t.date)}</span>
                  </p>
                </div>

                <span className={t.type === 'income' ? styles.amtPos : styles.amtNeg}>
                  {t.type === 'income' ? '+' : '−'}{formatCurrency(t.amount)}
                </span>

                <button
                  className={styles.deleteBtn}
                  onClick={() => handleDelete(t.id)}
                  disabled={deletingId === t.id}
                  aria-label={`Eliminar ${t.description}`}
                  title="Eliminar"
                >
                  {deletingId === t.id ? '…' : '✕'}
                </button>
              </li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  )
}
